import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push({ v, start, end });
    }

    // Dijkstra's setup
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const pq = new MinPriorityQueue({ priority: (x) => x.time });
    pq.enqueue({ node: 0, time: 0 });

    while (!pq.isEmpty()) {
        const { node: u, time: currentTime } = pq.dequeue().element;
        if (u === n - 1) {
            return currentTime;
        }
        if (currentTime > dist[u]) {
            continue;
        }

        // Option 1: Stay at current node (time +1)
        if (currentTime + 1 < dist[u]) {
            dist[u] = currentTime + 1;
            pq.enqueue({ node: u, time: currentTime + 1 });
        }

        // Option 2: Try all outgoing edges
        for (const { v, start, end } of adj[u]) {
            if (currentTime > end) {
                continue; // Edge is no longer available
            }
            const departureTime = Math.max(currentTime, start);
            const arrivalTime = departureTime + 1;
            if (arrivalTime < dist[v]) {
                dist[v] = arrivalTime;
                pq.enqueue({ node: v, time: arrivalTime });
            }
        }
    }

    return dist[n - 1] === Infinity ? -1 : dist[n - 1];
}

